#include<bits/stdc++.h>
using namespace std;
const long long mod = 1e9+7;
long long n,m,a[105][105],dp[105][105][105],sum[105][105],ans=1;
int main(){
    cin>>n>>m;
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++){
            char c;cin>>c;
            a[i][j]=a[i][j-1]+(c=='X');
        }
    for(int l=1;l<=m;l++)
        for(int r=l;r<=m;r++)
            if(a[n][r]-a[n][l-1]==0)dp[n][l][r]=1,ans++;
    for(int i=n-1;i>=1;i--){
        for(int j=0;j<=m;j++)sum[0][j]=0,sum[j][0]=0;
        for(int l=1;l<=m;l++)
            for(int r=l;r<=m;r++)
                sum[l][r]=(sum[l-1][r]+sum[l][r-1]-sum[l-1][r-1]+dp[i+1][l][r]+mod)%mod;
        for(int l=1;l<=m;l++)
            for(int r=l;r<=m;r++)
                if(a[i][r]-a[i][l-1]==0){
                    dp[i][l][r]=(sum[l][m]-sum[l][r-1]+mod)%mod;
                    ans=(ans+dp[i][l][r])%mod;
                }
    }
    cout<<ans;
    return 0;
}
